import { useNavigate } from 'react-router-dom';
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Home.css';

function Home() {
  const [showProfile, setShowProfile] = useState(false);
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  const [stats, setStats] = useState({
    totalPredictions: 0,
    avgSalary: 0,
    bestModelAccuracy: 0
  });

  // Fetch stats
  useEffect(() => {
    axios.get('http://localhost:5000/stats')
      .then(res => {
        setStats({
          totalPredictions: res.data.totalPredictions || 0,
          avgSalary: res.data.avgSalary || 0,
          bestModelAccuracy: res.data.bestModelAccuracy || 0
        });
      })
      .catch(err => console.log(err));
  }, []);

  // Check login
  useEffect(() => {
    const storedUser = localStorage.getItem("user");
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.clear();
    navigate('/login');
  };

  return (
    <div className="home-container">

      {/* NAVBAR */}
      <nav className="navbar">
        <h3>Dashboard</h3>

        <div className="right-section">
          <div
            className="profile-circle"
            onClick={() => setShowProfile(!showProfile)}
          >
            <span>{user?.name?.charAt(0) || "P"}</span>
          </div>

          {showProfile && (
            <div className="profile-card">
              <h3>Profile 👤</h3>
              <p><b>Name:</b> {user?.name}</p>
              <p><b>Email:</b> {user?.email}</p>`
              `
            </div>
          )}

          <button onClick={handleLogout} className="logout-btn">
            Logout
          </button>
        </div>
      </nav>

      {/* CONTENT */}
      <div className="main-content">
        <h2>Know your worth, predict with confidence 🚀</h2>

        <button onClick={() => navigate('/predict')}>
          New Salary Prediction
        </button>

        <div className="stats-container">
          <div className="stat-card" onClick={() => navigate("/my-history")}>
            <h3>Total Predictions</h3>
            <p>{stats.totalPredictions}</p>
          </div>

          <div className="stat-card">
            <h3>Average Salary</h3>
            <p>${stats.avgSalary}</p>
          </div>

          <div className="stat-card">
            <h3>Best Model Accuracy</h3>
            <p>{stats.bestModelAccuracy}%</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
